mapper.select:
SELECT b.track_id trackId, a.track_sn trackSn, b.track_nm trackNm, b.album_id album_id, b.disp_status_yn displayYn, b.agency_id agencyId, IF(b.title_yn = 'Y' , 'Y', 'N') titleYn, b.create_dtime createDateTime, b.update_dtime updateDateTime, f.album_img_size size, CONCAT(f.album_img_url, '?updateDate=', unix_timestamp(f.update_dtime)) AS url, f.update_dtime albumImgUpdateDateTime, IF(e.like_type_id is not null, 'Y', 'N') likeYn, IF(b.streaming_premium_yn = 'Y' OR b.pps_yn = 'Y', 'Y', 'N') holdbackYn, IF(b.adult_auth_need_track_yn = 'Y', 'Y', 'N') adultAuthYn, d.artist_id artistId, d.artist_nm artistNm, g.title albumTitle, h.artist_id repArtistId, h.artist_nm repArtistNm FROM ( SELECT mmct.track_id track_id, mmct.update_dtime update_dtime, mmct.track_sn track_sn FROM tb_member_chnl mmc INNER JOIN tb_map_member_chnl_track mmct ON mmc.member_chnl_id = mmct.member_chnl_id WHERE mmc.member_no = #{memberNo} AND mmc.character_no = #{characterNo} AND mmc.member_chnl_id = #{channelId} ORDER BY mmct.update_dtime DESC, mmct.track_sn ASC
LIMIT #{pageable.offset} , #{pageable.pageSize}
) a INNER JOIN tb_track b ON a.track_id = b.track_id LEFT OUTER JOIN ted_trackartist c ON b.track_id = c.track_id AND c.rp_yn = 'Y' AND c.db_sts = 'A' LEFT OUTER JOIN ted_artist d ON c.artist_id = d.artist_id LEFT OUTER JOIN tb_character_like e ON b.track_id = e.like_type_id AND e.character_no = #{characterNo} AND e.like_type = 'TRACK' LEFT OUTER JOIN tb_album_img f ON b.album_id = f.album_id LEFT OUTER JOIN ted_album g ON b.album_id = g.album_id LEFT OUTER JOIN ted_artist h ON b.reprsnt_artist_id = h.artist_id WHERE b.disp_status_yn = 'Y' ORDER BY a.update_dtime DESC , a.track_sn ASC, c.listorder ASC

		SELECT
			COUNT(*)
		FROM
			tb_member_chnl a INNER JOIN tb_map_member_chnl_track b
				ON a.member_chnl_id =b.member_chnl_id
        WHERE a.character_no = #{characterNo}
		AND a.member_no = #{memberNo}
		AND a.member_chnl_id = #{channelId}

